import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"54. Recall No Return To Workplace","description":"","frontmatter":{"title":"54. Recall No Return To Workplace","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","on-call","allowances"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/54-recall-no-return-to-workplace.md","filePath":"ebas/allied-health/hours-of-work/54-recall-no-return-to-workplace.md"}'),l={name:"ebas/allied-health/hours-of-work/54-recall-no-return-to-workplace.md"};function n(s,e,i,p,c,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_54-recall-no-return-to-workplace" tabindex="-1">54. Recall No Return To Workplace <a class="header-anchor" href="#_54-recall-no-return-to-workplace" aria-label="Permalink to &quot;54. Recall No Return To Workplace&quot;">​</a></h1><p><strong>54.1</strong> Non CATT areas</p><p><strong>(a)</strong> Where recall to duty can be managed without the Employee returning to the workplace (for example by telephone), <a href="/eba/ebas/allied-health/hours-of-work/53-recall-return-to-workplace.html">clause 53</a> will not apply and such Employee will be paid a minimum of one (1) hour of overtime for such recall work.</p><p><strong>(b)</strong> For subsequent recalls beyond the first hour, the Employee will be paid a minimum of one (1) hour of overtime, but multiple recalls within a discrete hour will not attract additional overtime.</p><p><strong>54.2</strong> Telephone recall CATT only</p><p><strong>(a)</strong> Employees engaged in on-call/recall for the provision of a crisis response (CATT type function) will be paid an allowance which is set out at <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a>, for each on-call period of twelve (12) hours or part thereof.</p><p><strong>(b)</strong> The allowance includes payment of work performed of up to one (1) hour’s aggregate duration for each on-call period.</p><p><strong>(c)</strong> For work performed in excess of an aggregate of one (1) hour during an on-call period, payment will be made at the normal overtime rate paid at the Employee’s substantive classification and increment level.</p><p><strong>(d)</strong> Telephone attendance is to be regarded as recall to duty.</p><p><strong>(e)</strong> Only one (1) Employee per team each night will be rostered on-call and in receipt of the allowance. No other team member (other than a psychiatrist) will be required or requested to provide out of hours service for that particular night.</p><p><strong>(f)</strong> Employees are to receive an uninterrupted break of at least eight (8) hours between the end of the recall and the next shift. If the eight (8) hour break is not observed double time will be paid until such break is observed.</p><p><strong>(g)</strong> The maximum period of on-call for CATT is to be 12 hours, with existing arrangements below the 12 hours not to be disturbed.</p><p><strong>(h)</strong> The Union and the VHIA acknowledge the unique nature of the on-call requirements for crisis response (CATT type functions) and that it is not comparable to any other health care arrangement or setting.</p>',13)])])}const m=o(l,[["render",n]]);export{d as __pageData,m as default};
